1	import { existsSync, mkdirSync } from "node:fs";
2	import { join, resolve } from "node:path";
3	import type {
4	  ConfigFile,
5	  CreateParams,
6	  CreateResult,
7	  DependenciesFile,
8	  HistoryResult,
9	  IndexEntry,
10	  IndexFile,
11	  InitResult,
12	  IssueId,
13	  IssueProperties,
14	  IssueStatus,
15	  ListParams,
16	  ListResult,
17	  UpdateParams,
18	  UpdateResult,
19	  UsersFile,
20	  ViewResult,
21	} from "../types";
22	import { ErrorCodes, TrackgenticError } from "./errors";
23	import { appendEvent, computeState, replayEvents } from "./events";
24	import { atomicWriteJSON } from "./file-io";
25	import { generateId } from "./id";
26	import { findEntry, insertEntry, readIndex, updateEntry, writeIndex } from "./index-manager";
27	import { resolveTrackerDir } from "./resolution";
28	
29	const TRACKGENTIC_DIR = ".trackgentic";
30	
31	/**
32	 * Default config.json contents.
33	 */
34	const DEFAULT_CONFIG: ConfigFile = {
35	  auth: {
36	    mode: "read-only",
37	    defaultUser: "anonymous",
38	  },
39	};
40	
41	/**
42	 * Default index.json contents.
43	 */
44	const DEFAULT_INDEX: IndexFile = {
45	  open: [],
46	  closed: [],
47	  childrenOf: {},
48	};
49	
50	/**
51	 * Default dependencies.json contents.
52	 */
53	const DEFAULT_DEPENDENCIES: DependenciesFile = {
54	  blockedBy: {},
55	  blocks: {},
56	};
57	
58	/**
59	 * Default users.json contents.
60	 */
61	const DEFAULT_USERS: UsersFile = {
62	  users: [],
63	};
64	
65	/**
66	 * Tracker — the main programmatic API for trackgentic.
67	 *
68	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
69	 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
70	 */
71	export class Tracker {
72	  private cwd: string;
73	
74	  constructor(cwd?: string) {
75	    this.cwd = cwd ?? process.cwd();
76	  }
77	
78	  /**
79	   * Initialize a new `.trackgentic/` directory in `cwd`.
80	   */
81	  async init(): Promise<InitResult> {
82	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
83	
84	    if (existsSync(trackerDir)) {
85	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
86	    }
87	
88	    mkdirSync(trackerDir, { recursive: true });
89	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
90	
91	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
92	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
93	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
94	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
95	
96	    return { result: "OK", path: resolve(trackerDir) };
97	  }
98	
99	  /**
100	   * Create a new issue.
101	   */
102	  async create(params: CreateParams): Promise<CreateResult> {
103	    const trackerDir = resolveTrackerDir(this.cwd);
104	    if (!trackerDir) {
105	      throw new TrackgenticError(
106	        ErrorCodes.NOT_INITIALIZED.result,
107	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
108	        ErrorCodes.NOT_INITIALIZED.exitCode,
109	      );
110	    }
111	
112	    const id = generateId();
113	    const issuePath = params.path ?? `issues/${id}.json`;
114	    const author = params.author ?? "anonymous";
115	    const now = new Date().toISOString();
116	
117	    const title = params.title;
118	    const description = params.description ?? "";
119	    const status: IssueStatus = params.status ?? "idea";
120	    const priority = params.priority ?? 3;
121	    const assignee = params.assignee ?? null;
122	    const parentId = params.parentId ?? null;
123	    const tags = params.tags ?? [];
124	
125	    // Build update content with only non-default values
126	    const updateContent: Partial<
127	      Pick<
128	        IssueProperties,
129	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
130	      >
131	    > & { title: string } = { title };
132	    if (description) updateContent.description = description;
133	    if (status !== "idea") updateContent.status = status;
134	    if (priority !== 3) updateContent.priority = priority;
135	    if (assignee !== null) updateContent.assignee = assignee;
136	    if (parentId !== null) updateContent.parentId = parentId;
137	    if (tags.length > 0) updateContent.tags = tags;
138	
139	    // Create issue file with two events: creation + update
140	    const creationEvent = { type: "creation" as const, timestamp: now, author };
141	    const updateEvent = {
142	      type: "update" as const,
143	      timestamp: now,
144	      author,
145	      content: updateContent,
146	    };
147	
148	    const issueFilePath = join(trackerDir, issuePath);
149	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
150	
151	    // Build index entry and insert into index
152	    const entry: IndexEntry = {
153	      id,
154	      title,
155	      path: issuePath,
156	      status,
157	      assignee,
158	      parentId,
159	      tags,
160	      priority,
161	    };
162	
163	    const index = await readIndex(trackerDir);
164	    const updatedIndex = insertEntry(index, entry);
165	    await writeIndex(trackerDir, updatedIndex);
166	
167	    return { id };
168	  }
169	
170	  /**
171	   * List issues from the index, with optional filters.
172	   */
173	  async list(params?: ListParams): Promise<ListResult> {
174	    const trackerDir = resolveTrackerDir(this.cwd);
175	    if (!trackerDir) {
176	      throw new TrackgenticError(
177	        ErrorCodes.NOT_INITIALIZED.result,
178	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
179	        ErrorCodes.NOT_INITIALIZED.exitCode,
180	      );
181	    }
182	
183	    const index = await readIndex(trackerDir);
184	
185	    // Determine source arrays based on params.status
186	    let entries: IndexEntry[];
187	    if (params?.status === "closed") {
188	      entries = index.closed;
189	    } else if (params?.status === "open") {
190	      entries = index.open;
191	    } else if (params?.status) {
192	      entries = index.open;
193	    } else {
194	      entries = [...index.open, ...index.closed];
195	    }
196	
197	    // Filter in memory
198	    let filtered = entries;
199	
200	    if (params?.status && params.status !== "open" && params.status !== "closed") {
201	      filtered = filtered.filter((e) => e.status === params.status);
202	    }
203	
204	    if (params?.assignee) {
205	      filtered = filtered.filter((e) => e.assignee === params.assignee);
206	    }
207	
208	    if (params?.tags && params.tags.length > 0) {
209	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
210	    }
211	
212	    if (params?.parentId !== undefined) {
213	      if (params.parentId === null) {
214	        filtered = filtered.filter((e) => e.parentId === null);
215	      } else {
216	        filtered = filtered.filter((e) => e.parentId === params.parentId);
217	      }
218	    }
219	
220	    // Sort: priority ASC → id ASC
221	    filtered.sort((a, b) => {
222	      if (a.priority !== b.priority) return a.priority - b.priority;
223	      return a.id.localeCompare(b.id);
224	    });
225	
226	    return filtered;
227	  }
228	
229	  /**
230	   * View a single issue's full computed state.
231	   */
232	  async view(id: IssueId): Promise<ViewResult> {
233	    const trackerDir = resolveTrackerDir(this.cwd);
234	    if (!trackerDir) {
235	      throw new TrackgenticError(
236	        ErrorCodes.NOT_INITIALIZED.result,
237	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
238	        ErrorCodes.NOT_INITIALIZED.exitCode,
239	      );
240	    }
241	
242	    const index = await readIndex(trackerDir);
243	    const entry = findEntry(index, id);
244	    if (!entry) {
245	      throw new TrackgenticError(
246	        ErrorCodes.NOT_FOUND.result,
247	        `Issue ${id} not found in index.`,
248	        ErrorCodes.NOT_FOUND.exitCode,
249	      );
250	    }
251	
252	    const issueFilePath = join(trackerDir, entry.path);
253	    if (!existsSync(issueFilePath)) {
254	      throw new TrackgenticError(
255	        ErrorCodes.ISSUE_MISSING.result,
256	        `Issue file for ${id} is missing.`,
257	        ErrorCodes.ISSUE_MISSING.exitCode,
258	      );
259	    }
260	
261	    const events = await replayEvents(issueFilePath);
262	    return computeState(events, id);
263	  }
264	
265	  /**
266	   * Update an existing issue.
267	   */
268	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
269	    const trackerDir = resolveTrackerDir(this.cwd);
270	    if (!trackerDir) {
271	      throw new TrackgenticError(
272	        ErrorCodes.NOT_INITIALIZED.result,
273	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
274	        ErrorCodes.NOT_INITIALIZED.exitCode,
275	      );
276	    }
277	
278	    // Validate at least one field provided (besides author)
279	    const hasField =
280	      params.title !== undefined ||
281	      params.description !== undefined ||
282	      params.status !== undefined ||
283	      params.assignee !== undefined ||
284	      params.tags !== undefined ||
285	      params.priority !== undefined ||
286	      params.parentId !== undefined;
287	
288	    if (!hasField) {
289	      throw new TrackgenticError(
290	        ErrorCodes.INVALID_PARAMS.result,
291	        "At least one field must be provided for update.",
292	        ErrorCodes.INVALID_PARAMS.exitCode,
293	      );
294	    }
295	
296	    const index = await readIndex(trackerDir);
297	    const entry = findEntry(index, id);
298	    if (!entry) {
299	      throw new TrackgenticError(
300	        ErrorCodes.NOT_FOUND.result,
301	        `Issue ${id} not found in index.`,
302	        ErrorCodes.NOT_FOUND.exitCode,
303	      );
304	    }
305	
306	    const issueFilePath = join(trackerDir, entry.path);
307	    if (!existsSync(issueFilePath)) {
308	      throw new TrackgenticError(
309	        ErrorCodes.ISSUE_MISSING.result,
310	        `Issue file for ${id} is missing.`,
311	        ErrorCodes.ISSUE_MISSING.exitCode,
312	      );
313	    }
314	
315	    // Build update event content with only the provided fields
316	    const content: Partial<
317	      Pick<
318	        IssueProperties,
319	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
320	      >
321	    > = {};
322	    if (params.title !== undefined) content.title = params.title;
323	    if (params.description !== undefined) content.description = params.description;
324	    if (params.status !== undefined) content.status = params.status;
325	    if (params.assignee !== undefined) content.assignee = params.assignee;
326	    if (params.tags !== undefined) content.tags = params.tags;
327	    if (params.priority !== undefined) content.priority = params.priority;
328	    if (params.parentId !== undefined) content.parentId = params.parentId;
329	
330	    const author = params.author ?? "anonymous";
331	    const now = new Date().toISOString();
332	
333	    const updateEvent = {
334	      type: "update" as const,
335	      timestamp: now,
336	      author,
337	      content,
338	    };
339	
340	    // Append event to issue file
341	    await appendEvent(issueFilePath, updateEvent);
342	
343	    // Recompute state from all events
344	    const events = await replayEvents(issueFilePath);
345	    const computed = computeState(events, id);
346	
347	    // Update index entry with new computed values
348	    const updatedIndex = updateEntry(index, id, {
349	      title: computed.title,
350	      status: computed.status,
351	      assignee: computed.assignee,
352	      parentId: computed.parentId,
353	      tags: computed.tags,
354	      priority: computed.priority,
355	    });
356	
357	    await writeIndex(trackerDir, updatedIndex);
358	
359	    return { result: "OK" };
360	  }
361	
362	  /**
363	   * Get the raw event history for an issue.
364	   */
365	  async history(id: IssueId): Promise<HistoryResult> {
366	    const trackerDir = resolveTrackerDir(this.cwd);
367	    if (!trackerDir) {
368	      throw new TrackgenticError(
369	        ErrorCodes.NOT_INITIALIZED.result,
370	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
371	        ErrorCodes.NOT_INITIALIZED.exitCode,
372	      );
373	    }
374	
375	    const index = await readIndex(trackerDir);
376	    const entry = findEntry(index, id);
377	    if (!entry) {
378	      throw new TrackgenticError(
379	        ErrorCodes.NOT_FOUND.result,
380	        `Issue ${id} not found in index.`,
381	        ErrorCodes.NOT_FOUND.exitCode,
382	      );
383	    }
384	
385	    const issueFilePath = join(trackerDir, entry.path);
386	    if (!existsSync(issueFilePath)) {
387	      throw new TrackgenticError(
388	        ErrorCodes.ISSUE_MISSING.result,
389	        `Issue file for ${id} is missing.`,
390	        ErrorCodes.ISSUE_MISSING.exitCode,
391	      );
392	    }
393	
394	    return replayEvents(issueFilePath);
395	  }
396	}
