1	import { TrackgenticError } from "../../core/errors";
2	import { Tracker } from "../../core/tracker";
3	import type { CreateParams, IssueStatus } from "../../types";
4	import { writeStderr, writeStdout } from "../output";
5	
6	interface CreateOptions {
7	  description?: string;
8	  assignee?: string;
9	  tags?: string;
10	  status?: string;
11	  priority?: string;
12	  parentId?: string;
13	  path?: string;
14	}
15	
16	/**
17	 * Handler for the `trackgentic create <title>` command.
18	 */
19	export async function createAction(title: string, options: CreateOptions): Promise<void> {
20	  try {
21	    const tracker = new Tracker();
22	    const params: CreateParams = { title };
23	
24	    if (options.description !== undefined) params.description = options.description;
25	    if (options.assignee !== undefined) params.assignee = options.assignee;
26	    if (options.tags !== undefined) {
27	      params.tags = options.tags.split(",").map((t) => t.trim());
28	    }
29	    if (options.status !== undefined) params.status = options.status as IssueStatus;
30	    if (options.priority !== undefined) {
31	      params.priority = Number.parseInt(options.priority, 10) as 1 | 2 | 3 | 4 | 5;
32	    }
33	    if (options.parentId !== undefined) params.parentId = options.parentId;
34	    if (options.path !== undefined) params.path = options.path;
35	
36	    const result = await tracker.create(params);
37	    writeStdout(result);
38	    process.exit(0);
39	  } catch (err) {
40	    if (err instanceof TrackgenticError) {
41	      writeStderr({ result: err.result, message: err.message });
42	      process.exit(err.exitCode);
43	    }
44	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
45	    process.exit(1);
46	  }
47	}
