1	import { TrackgenticError } from "../../core/errors";
2	import { Tracker } from "../../core/tracker";
3	import type { IssueStatus, ListParams } from "../../types";
4	import { writeStderr, writeStdout } from "../output";
5	
6	interface ListOptions {
7	  status?: string;
8	  assignee?: string;
9	  tags?: string;
10	  parentId?: string;
11	}
12	
13	/**
14	 * Handler for the `trackgentic list` command.
15	 */
16	export async function listAction(options: ListOptions): Promise<void> {
17	  try {
18	    const tracker = new Tracker();
19	    const params: ListParams = {};
20	
21	    if (options.status !== undefined) {
22	      params.status = options.status as IssueStatus | "open";
23	    }
24	    if (options.assignee !== undefined) params.assignee = options.assignee;
