1	/**
2	 * Write a JSON result to stdout.
3	 */
4	export function writeStdout(data: unknown): void {
5	  process.stdout.write(`${JSON.stringify(data, null, 2)}\n`);
6	}
7	
8	/**
9	 * Write a JSON error to stderr.
10	 */
11	export function writeStderr(data: unknown): void {
