1	import { TrackgenticError } from "../../core/errors";
2	import { Tracker } from "../../core/tracker";
3	import type { IssueStatus, UpdateParams } from "../../types";
4	import { writeStderr, writeStdout } from "../output";
5	
6	interface UpdateOptions {
7	  title?: string;
8	  description?: string;
9	  status?: string;
10	  assignee?: string;
11	  tags?: string;
12	  priority?: string;
13	  parentId?: string;
14	}
15	
16	/**
17	 * Handler for the `trackgentic update <issueId>` command.
18	 */
19	export async function updateAction(issueId: string, options: UpdateOptions): Promise<void> {
20	  try {
21	    // Build params — only include fields that were actually provided
22	    const params: UpdateParams = {};
23	
24	    if (options.title !== undefined) params.title = options.title;
25	    if (options.description !== undefined) params.description = options.description;
26	    if (options.status !== undefined) params.status = options.status as IssueStatus;
27	    if (options.assignee !== undefined) params.assignee = options.assignee;
28	    if (options.tags !== undefined) {
29	      params.tags = options.tags.split(",").map((t) => t.trim());
30	    }
31	    if (options.priority !== undefined) {
32	      params.priority = Number.parseInt(options.priority, 10) as 1 | 2 | 3 | 4 | 5;
33	    }
34	    if (options.parentId !== undefined) {
35	      params.parentId = options.parentId === "null" ? null : options.parentId;
36	    }
37	
38	    // Validate at least one flag provided
39	    if (Object.keys(params).length === 0) {
40	      writeStderr({
41	        result: "INVALID_PARAMS",
42	        message: "At least one field must be provided for update.",
43	      });
44	      process.exit(10);
45	    }
46	
47	    const tracker = new Tracker();
48	    const result = await tracker.update(issueId, params);
49	    writeStdout(result);
50	    process.exit(0);
51	  } catch (err) {
52	    if (err instanceof TrackgenticError) {
53	      writeStderr({ result: err.result, message: err.message });
54	      process.exit(err.exitCode);
55	    }
56	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
57	    process.exit(1);
58	  }
59	}
