import { readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { Tracker } from "../src/core/tracker";
import type { ConfigFile } from "../src/types";

/**
 * Initialize a tracker with `open` auth mode.
 * This allows all operations without requiring a token.
 * Used for Phase 2 tests that don't test auth.
 */
export async function initOpenTracker(testDir: string): Promise<Tracker> {
  const tracker = new Tracker(testDir);
  await tracker.init();

  // Override config to use open mode
  const configPath = join(testDir, ".trackgentic", "config.json");
  const config: ConfigFile = {
    auth: {
      mode: "open",
      defaultUser: "anonymous",
    },
  };
  writeFileSync(configPath, `${JSON.stringify(config, null, 2)}\n`, "utf-8");

  return tracker;
}

/**
 * Set config auth mode for a tracker directory.
 */
export function setAuthMode(
  testDir: string,
  mode: "open" | "read-only" | "strict",
  defaultUser = "anonymous",
): void {
  const configPath = join(testDir, ".trackgentic", "config.json");
  const config: ConfigFile = {
    auth: {
      mode,
      defaultUser,
    },
  };
  writeFileSync(configPath, `${JSON.stringify(config, null, 2)}\n`, "utf-8");
}

/**
 * Set the TRACKGENTIC_USER_TOKEN env var for a test.
 * Returns a cleanup function to restore the original value.
 */
export function setEnvToken(token: string | undefined): () => void {
  const original = process.env.TRACKGENTIC_USER_TOKEN;
  if (token !== undefined) {
    process.env.TRACKGENTIC_USER_TOKEN = token;
  } else {
    delete process.env.TRACKGENTIC_USER_TOKEN;
  }
  return () => {
    if (original !== undefined) {
      process.env.TRACKGENTIC_USER_TOKEN = original;
    } else {
      delete process.env.TRACKGENTIC_USER_TOKEN;
    }
  };
}

/**
 * Set config for CLI tests (modifies config.json after init).
 */
export function setCLIConfig(
  testDir: string,
  mode: "open" | "read-only" | "strict",
  defaultUser = "anonymous",
): void {
  const configPath = join(testDir, ".trackgentic", "config.json");
  const config: ConfigFile = {
    auth: {
      mode,
      defaultUser,
    },
  };
  writeFileSync(configPath, `${JSON.stringify(config, null, 2)}\n`, "utf-8");
}
